# euler_solver.py  —  Claude Code output
def euler_check(graph):
    degrees = {v: len(edges)
               for v,edges in graph.items()}
    odd_vertices = [v for v,d in degrees.items()
                    if d % 2 != 0]  # Euler condition
    if len(odd_vertices) == 0:
        return 'Euler circuit exists', degrees
    elif len(odd_vertices) == 2:
        return 'Euler path exists', degrees
    else:
        return 'No Euler path or circuit', degrees

